-- GameManager.server.lua\n-- Script principal del servidor\n-- Va en ServerScriptService\n\nlocal ReplicatedStorage = game:GetService(\"ReplicatedStorage\")\nlocal Players = game:GetService(\"Players\")\n\n-- Importar módulos\nlocal MoneyModule = require(ReplicatedStorage:WaitForChild(\"MoneyModule\"))\nlocal MissionModule = require(ReplicatedStorage:WaitForChild(\"MissionModule\"))\n\n-- Variables globales\nlocal INITIAL_MONEY = 100\nlocal GAME_TIME_SCALE = 1\n\nprint(\"[GameManager] Inicializando Finuturo 3D en ROBLOX...\")\n\n-- Inicializar misiones\nMissionModule:InitializeMissions()\n\n-- Eventos cuando un jugador entra\nPlayers.PlayerAdded:Connect(function(player)\n\tprint(\"[GameManager] Jugador \" .. player.Name .. \" entró al juego\")\n\t\n\t-- Dar dinero inicial\n\tMoneyModule:AddMoney(player, INITIAL_MONEY)\n\t\n\t-- Crear carpeta de datos del jugador\n\tlocal leaderstats = Instance.new(\"Folder\")\n\tleaderstats.Name = \"leaderstats\"\n\tleaderstats.Parent = player\n\t\n\t-- Dinero\n\tlocal money = Instance.new(\"IntValue\")\n\tmoney.Name = \"Dinero\"\n\tmoney.Value = INITIAL_MONEY\n\tmoney.Parent = leaderstats\n\t\n\t-- Nivel\n\tlocal level = Instance.new(\"IntValue\")\n\tlevel.Name = \"Nivel\"\n\tlevel.Value = 1\n\tlevel.Parent = leaderstats\n\t\n\t-- Experiencia\n\tlocal experience = Instance.new(\"IntValue\")\n\texperience.Name = \"XP\"\n\texperience.Value = 0\n\texperience.Parent = leaderstats\nend)\n\n-- Eventos cuando un jugador sale\nPlayers.PlayerRemoving:Connect(function(player)\n\tprint(\"[GameManager] Jugador \" .. player.Name .. \" salió del juego\")\nend)\n\nprint(\"[GameManager] Sistema listo para jugar\")\n", "path": "scripts/GameManager.server.lua